/** Core color types and conversion utilities. */

export type RGB = { r: number; g: number; b: number }
export type HSL = { h: number; s: number; l: number }

export type ColorValue = {
  hex: string
  rgb: RGB
  hsl: HSL
}

/** Clamp a number to [min, max]. */
const clamp = (n: number, min: number, max: number): number =>
  Math.min(max, Math.max(min, n))

/** Parse a hex string (with or without #) to RGB. */
export const hexToRgb = (hex: string): RGB => {
  const clean = hex.replace(/^#/, '')
  const expanded =
    clean.length === 3
      ? clean
          .split('')
          .map((c) => c + c)
          .join('')
      : clean
  const n = parseInt(expanded, 16)
  return {
    r: (n >> 16) & 0xff,
    g: (n >> 8) & 0xff,
    b: n & 0xff,
  }
}

/** Convert RGB to hex string (with #). */
export const rgbToHex = (rgb: RGB): string => {
  const toHex = (v: number) =>
    clamp(Math.round(v), 0, 255).toString(16).padStart(2, '0')
  return `#${toHex(rgb.r)}${toHex(rgb.g)}${toHex(rgb.b)}`
}

/** Convert RGB to HSL. Returns h in [0,360), s and l in [0,100]. */
export const rgbToHsl = (rgb: RGB): HSL => {
  const r = rgb.r / 255
  const g = rgb.g / 255
  const b = rgb.b / 255
  const max = Math.max(r, g, b)
  const min = Math.min(r, g, b)
  const d = max - min
  const l = (max + min) / 2

  if (d === 0) return { h: 0, s: 0, l: Math.round(l * 100) }

  const s = l > 0.5 ? d / (2 - max - min) : d / (max + min)
  let h = 0
  if (max === r) h = ((g - b) / d + (g < b ? 6 : 0)) / 6
  else if (max === g) h = ((b - r) / d + 2) / 6
  else h = ((r - g) / d + 4) / 6

  return {
    h: Math.round(h * 360),
    s: Math.round(s * 100),
    l: Math.round(l * 100),
  }
}

/** Convert HSL to RGB. Expects h in [0,360), s and l in [0,100]. */
export const hslToRgb = (hsl: HSL): RGB => {
  const s = hsl.s / 100
  const l = hsl.l / 100
  const c = (1 - Math.abs(2 * l - 1)) * s
  const x = c * (1 - Math.abs(((hsl.h / 60) % 2) - 1))
  const m = l - c / 2
  let r1 = 0,
    g1 = 0,
    b1 = 0
  const h = hsl.h % 360

  if (h < 60) [r1, g1, b1] = [c, x, 0]
  else if (h < 120) [r1, g1, b1] = [x, c, 0]
  else if (h < 180) [r1, g1, b1] = [0, c, x]
  else if (h < 240) [r1, g1, b1] = [0, x, c]
  else if (h < 300) [r1, g1, b1] = [x, 0, c]
  else [r1, g1, b1] = [c, 0, x]

  return {
    r: Math.round((r1 + m) * 255),
    g: Math.round((g1 + m) * 255),
    b: Math.round((b1 + m) * 255),
  }
}

/** Build a full ColorValue from a hex string. */
export const colorFromHex = (hex: string): ColorValue => {
  const rgb = hexToRgb(hex)
  const hsl = rgbToHsl(rgb)
  return { hex: rgbToHex(rgb), rgb, hsl }
}

/** Build a full ColorValue from HSL values. */
export const colorFromHsl = (hsl: HSL): ColorValue => {
  const rgb = hslToRgb(hsl)
  return { hex: rgbToHex(rgb), rgb, hsl }
}

/** Normalize a hue to [0, 360). */
export const normalizeHue = (h: number): number => ((h % 360) + 360) % 360

/** Format RGB as a CSS string. */
export const formatRgb = (rgb: RGB): string =>
  `rgb(${rgb.r}, ${rgb.g}, ${rgb.b})`

/** Format HSL as a CSS string. */
export const formatHsl = (hsl: HSL): string =>
  `hsl(${hsl.h}, ${hsl.s}%, ${hsl.l}%)`

/** Validate a hex color string. */
export const isValidHex = (hex: string): boolean =>
  /^#?([0-9a-fA-F]{3}|[0-9a-fA-F]{6})$/.test(hex)

/** Color harmony generators based on color theory. */

import {
  type ColorValue,
  type HSL,
  colorFromHsl,
  colorFromHex,
  normalizeHue,
  isValidHex,
} from './color'

export type HarmonyType =
  | 'complementary'
  | 'analogous'
  | 'triadic'
  | 'split-complementary'
  | 'tetradic'

export type Palette = {
  name: HarmonyType
  base: ColorValue
  colors: ColorValue[]
}

/** Shift a hue by the given degrees. */
const shiftHue = (hsl: HSL, degrees: number): HSL => ({
  h: normalizeHue(hsl.h + degrees),
  s: hsl.s,
  l: hsl.l,
})

/** Complementary: base + opposite (180°). */
const complementary = (base: ColorValue): ColorValue[] => [
  base,
  colorFromHsl(shiftHue(base.hsl, 180)),
]

/** Analogous: base + two neighbors (±30°). */
const analogous = (base: ColorValue): ColorValue[] => [
  colorFromHsl(shiftHue(base.hsl, -30)),
  base,
  colorFromHsl(shiftHue(base.hsl, 30)),
]

/** Triadic: three colors evenly spaced (120° apart). */
const triadic = (base: ColorValue): ColorValue[] => [
  base,
  colorFromHsl(shiftHue(base.hsl, 120)),
  colorFromHsl(shiftHue(base.hsl, 240)),
]

/** Split-complementary: base + two colors flanking the complement (±150°). */
const splitComplementary = (base: ColorValue): ColorValue[] => [
  base,
  colorFromHsl(shiftHue(base.hsl, 150)),
  colorFromHsl(shiftHue(base.hsl, 210)),
]

/** Tetradic (rectangular): four colors forming a rectangle (0°, 60°, 180°, 240°). */
const tetradic = (base: ColorValue): ColorValue[] => [
  base,
  colorFromHsl(shiftHue(base.hsl, 60)),
  colorFromHsl(shiftHue(base.hsl, 180)),
  colorFromHsl(shiftHue(base.hsl, 240)),
]

const generators: Record<HarmonyType, (base: ColorValue) => ColorValue[]> = {
  complementary,
  analogous,
  triadic,
  'split-complementary': splitComplementary,
  tetradic,
}

/** Generate a palette from a hex color and harmony type. */
export const generatePalette = (
  hexInput: string,
  harmony: HarmonyType
): Palette => {
  if (!isValidHex(hexInput)) {
    throw new Error(`Invalid hex color: ${hexInput}`)
  }
  const base = colorFromHex(hexInput)
  const gen = generators[harmony]
  return {
    name: harmony,
    base,
    colors: gen(base),
  }
}

/** Generate all harmony palettes for a given hex color. */
export const generateAllPalettes = (hexInput: string): Palette[] => {
  const types: HarmonyType[] = [
    'complementary',
    'analogous',
    'triadic',
    'split-complementary',
    'tetradic',
  ]
  return types.map((t) => generatePalette(hexInput, t))
}

/** WCAG contrast ratio checker. */

import type { RGB, ColorValue } from './color'

export type WcagLevel = 'AAA' | 'AA' | 'Fail'

export type ContrastResult = {
  ratio: number
  normalText: WcagLevel
  largeText: WcagLevel
  color1: ColorValue
  color2: ColorValue
}

/**
 * Compute relative luminance of an sRGB color per WCAG 2.1.
 * https://www.w3.org/TR/WCAG21/#dfn-relative-luminance
 */
const relativeLuminance = (rgb: RGB): number => {
  const linearize = (channel: number): number => {
    const s = channel / 255
    return s <= 0.04045 ? s / 12.92 : Math.pow((s + 0.055) / 1.055, 2.4)
  }
  const r = linearize(rgb.r)
  const g = linearize(rgb.g)
  const b = linearize(rgb.b)
  return 0.2126 * r + 0.7152 * g + 0.0722 * b
}

/**
 * Compute the contrast ratio between two colors.
 * Returns a value between 1 and 21.
 */
export const contrastRatio = (a: RGB, b: RGB): number => {
  const l1 = relativeLuminance(a)
  const l2 = relativeLuminance(b)
  const lighter = Math.max(l1, l2)
  const darker = Math.min(l1, l2)
  return (lighter + 0.05) / (darker + 0.05)
}

/** Determine WCAG level for normal text (>= 4.5 AA, >= 7 AAA). */
const normalTextLevel = (ratio: number): WcagLevel => {
  if (ratio >= 7) return 'AAA'
  if (ratio >= 4.5) return 'AA'
  return 'Fail'
}

/** Determine WCAG level for large text (>= 3 AA, >= 4.5 AAA). */
const largeTextLevel = (ratio: number): WcagLevel => {
  if (ratio >= 4.5) return 'AAA'
  if (ratio >= 3) return 'AA'
  return 'Fail'
}

/** Check WCAG contrast compliance between two colors. */
export const checkContrast = (
  color1: ColorValue,
  color2: ColorValue
): ContrastResult => {
  const ratio = contrastRatio(color1.rgb, color2.rgb)
  return {
    ratio: Math.round(ratio * 100) / 100,
    normalText: normalTextLevel(ratio),
    largeText: largeTextLevel(ratio),
    color1,
    color2,
  }
}

