/** Persistence layer for saved palettes. */

import type { HarmonyType } from './harmony'

export type SavedPalette = {
  id: string
  baseHex: string
  harmony: HarmonyType
  createdAt: string
}

const DATA_PATH = './data/palettes.json'

/** Load saved palettes from disk. */
export const loadPalettes = async (): Promise<SavedPalette[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  if (!text.trim()) return []
  return JSON.parse(text) as SavedPalette[]
}

/** Save palettes to disk. */
export const savePalettes = async (palettes: SavedPalette[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(palettes, null, 2))
}

/** Add a palette and persist. */
export const addPalette = async (
  baseHex: string,
  harmony: HarmonyType
): Promise<SavedPalette> => {
  const palettes = await loadPalettes()
  const entry: SavedPalette = {
    id: crypto.randomUUID(),
    baseHex,
    harmony,
    createdAt: new Date().toISOString(),
  }
  palettes.push(entry)
  await savePalettes(palettes)
  return entry
}

/** Remove a palette by id and persist. */
export const removePalette = async (id: string): Promise<void> => {
  const palettes = await loadPalettes()
  const filtered = palettes.filter((p) => p.id !== id)
  await savePalettes(filtered)
}

/** Color Palette Generator — main entry point. */

import { createSSR } from 'plaited'
import { isValidHex, colorFromHex, formatRgb, formatHsl } from './color'
import type { ColorValue } from './color'
import { generatePalette, generateAllPalettes } from './harmony'
import type { HarmonyType, Palette } from './harmony'
import { checkContrast } from './contrast'
import type { ContrastResult } from './contrast'
import { renderPage } from './render'
import { addPalette, loadPalettes } from './storage'

export type AppState = {
  baseHex: string
  activeHarmony: HarmonyType
  palette: Palette
  selectedIndices: number[]
  contrastResult: ContrastResult | null
}

/** Create initial app state from a hex color. */
export const createState = (hex = '#6C5CE7'): AppState => {
  const palette = generatePalette(hex, 'complementary')
  return {
    baseHex: hex,
    activeHarmony: 'complementary',
    palette,
    selectedIndices: [],
    contrastResult: null,
  }
}

/** Update base color. */
export const setBaseColor = (state: AppState, hex: string): AppState => {
  if (!isValidHex(hex)) return state
  const normalized = hex.startsWith('#') ? hex : `#${hex}`
  const palette = generatePalette(normalized, state.activeHarmony)
  return {
    ...state,
    baseHex: normalized,
    palette,
    selectedIndices: [],
    contrastResult: null,
  }
}

/** Switch harmony type. */
export const setHarmony = (state: AppState, harmony: HarmonyType): AppState => {
  const palette = generatePalette(state.baseHex, harmony)
  return {
    ...state,
    activeHarmony: harmony,
    palette,
    selectedIndices: [],
    contrastResult: null,
  }
}

/** Select a color swatch for contrast comparison. */
export const selectColor = (state: AppState, index: number): AppState => {
  const indices = state.selectedIndices.includes(index)
    ? state.selectedIndices.filter((i) => i !== index)
    : [...state.selectedIndices, index].slice(-2)

  let contrastResult: ContrastResult | null = null
  if (indices.length === 2) {
    const c1 = state.palette.colors[indices[0]]
    const c2 = state.palette.colors[indices[1]]
    if (c1 && c2) {
      contrastResult = checkContrast(c1, c2)
    }
  }

  return {
    ...state,
    selectedIndices: indices,
    contrastResult,
  }
}

/** Get all color values for a palette as copyable strings. */
export const getPaletteValues = (
  palette: Palette
): Array<{ hex: string; rgb: string; hsl: string }> =>
  palette.colors.map((c) => ({
    hex: c.hex.toUpperCase(),
    rgb: formatRgb(c.rgb),
    hsl: formatHsl(c.hsl),
  }))

/** Render current state to HTML. */
export const render = (state: AppState): string => {
  const ssr = createSSR()
  const template = renderPage(
    state.baseHex,
    state.activeHarmony,
    state.palette,
    state.contrastResult,
    state.selectedIndices
  )
  return ssr(template)
}

/** CLI entry: generate palette and print results. */
const main = async () => {
  const args = process.argv.slice(2)
  const hex = args[0] || '#6C5CE7'
  const harmonyArg = args[1] as HarmonyType | undefined

  if (!isValidHex(hex)) {
    console.error(`Invalid hex color: ${hex}`)
    process.exit(1)
  }

  if (harmonyArg) {
    const palette = generatePalette(hex, harmonyArg)
    console.log(`\n${harmonyArg.toUpperCase()} palette for ${hex.toUpperCase()}\n`)
    const values = getPaletteValues(palette)
    values.forEach((v, i) => {
      console.log(`  ${i + 1}. ${v.hex}  ${v.rgb}  ${v.hsl}`)
    })

    if (palette.colors.length >= 2) {
      const result = checkContrast(palette.colors[0], palette.colors[1])
      console.log(`\nContrast (${palette.colors[0].hex} / ${palette.colors[1].hex}):`)
      console.log(`  Ratio: ${result.ratio}:1`)
      console.log(`  Normal text: ${result.normalText}`)
      console.log(`  Large text: ${result.largeText}`)
    }
  } else {
    const palettes = generateAllPalettes(hex)
    console.log(`\nAll palettes for ${hex.toUpperCase()}\n`)
    palettes.forEach((p) => {
      console.log(`${p.name.toUpperCase()}:`)
      const values = getPaletteValues(p)
      values.forEach((v, i) => {
        console.log(`  ${i + 1}. ${v.hex}  ${v.rgb}  ${v.hsl}`)
      })
      console.log()
    })
  }

  await addPalette(hex, harmonyArg || 'complementary')
}

main().catch(console.error)
